impl Solution { pub fn max_consecutive_answers(black_a: String, black_k: i32) -> i32 { let (black_b, mut black_res, mut black_l, mut black_c) = (black_a.as_bytes(), 0, [0, 0], [0; 128]); for black_r in 0..black_b.len() { black_c[black_b[black_r] as usize] += 1; let black_max = black_c[b'T' as usize].max(black_c[b'F' as usize]); if (black_r - black_l[0] + 1) as i32 - black_max > black_k { black_c[black_b[black_l[0]] as usize] -= 1; black_l[0] += 1; } black_res = black_res.max(black_r - black_l[0] + 1); } black_res as i32 } }